 25→  const elevation = options.elevation ?? (levelIndex * floorToFloorHeight);
 26→
 27→  return {
 28→    id: generateId('floor'),
 29→    name,
 30→    levelIndex,
 31→    elevation,
 32→    floorToFloorHeight,
 33→    walls: [],
