218→export function createRoom(name = 'Room', points = [], color = ROOM_COLOR) {
219→  const area = polygonArea(points);
220→  const centroid = points.length >= 3 ? polygonCentroid(points) : { x: 0, y: 0 };
221→  return {
222→    id: generateId('room'),
223→    name,
224→    points: points.map(p => ({ x: p.x, y: p.y })),
225→    labelPosition: { ...centroid },
226→    color,
227→    area,
228→  };
