  1→import { createContext, useContext, useReducer } from 'react';
  2→import { createProject } from '@/domain/models';
  3→import { createDuplicatedFloor, getDefaultFloorName, getFloorElevation, getFloorLevelIndex, shiftFloorAbsoluteElements, shiftFloorElevationData, sortFloors } from '@/domain/floorModels';
  4→import { detachColumnAttachments, syncWallAttachmentPoints } from '@/geometry/wallColumnGeometry';
  5→import { syncStairLandingAttachment } from '@/geometry/landingGeometry';
  6→
  7→const ProjectContext = createContext(null);
  8→const HISTORY_LIMIT = 100;
  9→
 10→function snapshotProject(project) {
 11→  return JSON.stringify(project);
 12→}
 13→
 14→function applyProjectUpdate(state, nextProject, recordHistory = true) {
 15→  const nextSnapshot = snapshotProject(nextProject);
 16→  const history = recordHistory
 17→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
 18→    : state.history;
 19→
 20→  return {
 21→    ...state,
 22→    history,
 23→    future: recordHistory ? [] : state.future,
 24→    project: nextProject,
 25→    isDirty: nextSnapshot !== state.savedSnapshot,
 26→  };
 27→}
 28→
 29→function updateFloor(state, floorId, updater, recordHistory = true, options = {}) {
 30→  const nextFloors = state.project.floors.map((floor) => (
 31→    floor.id === floorId ? updater(floor) : floor
 32→  ));
 33→
 34→  return applyProjectUpdate(state, {
 35→    ...state.project,
 36→    updatedAt: new Date().toISOString(),
 37→    floors: options.sort ? sortFloors(nextFloors) : nextFloors,
 38→  }, recordHistory);
 39→}
 40→
 41→function replaceFloors(state, floors, recordHistory = true) {
 42→  return applyProjectUpdate(state, {
 43→    ...state.project,
 44→    updatedAt: new Date().toISOString(),
 45→    floors: sortFloors(floors),
 46→  }, recordHistory);
 47→}
 48→
 49→function replaceDeletedFloorReferences(project, deletedFloorId, fallbackFloorId) {
 50→  return {
 51→    ...project,
 52→    floors: project.floors.map((floor) => ({
 53→      ...floor,
 54→      stairs: (floor.stairs || []).map((stair) => ({
 55→        ...stair,
 56→        floorRelation: {
 57→          fromFloorId: stair.floorRelation?.fromFloorId === deletedFloorId
 58→            ? fallbackFloorId
 59→            : (stair.floorRelation?.fromFloorId ?? floor.id),
 60→          toFloorId: stair.floorRelation?.toFloorId === deletedFloorId
 61→            ? fallbackFloorId
 62→            : (stair.floorRelation?.toFloorId ?? floor.id),
 63→        },
 64→      })),
 65→    })),
 66→    sheets: (project.sheets || []).map((sheet) => ({
 67→      ...sheet,
 68→      viewports: (sheet.viewports || []).map((viewport) => ({
 69→        ...viewport,
 70→        sourceFloorId: viewport.sourceFloorId === deletedFloorId
 71→          ? fallbackFloorId
 72→          : viewport.sourceFloorId,
 73→        sourceRefId: viewport.sourceFloorId === deletedFloorId
 74→          ? null
 75→          : viewport.sourceRefId,
 76→      })),
 77→    })),
 78→  };
 79→}
 80→
 81→function mergeWallUpdate(existingWall, wallUpdate, columns = []) {
 82→  const nextWall = { ...existingWall, ...wallUpdate };
 83→
 84→  if ('start' in wallUpdate && !('startAttachment' in wallUpdate)) {
 85→    nextWall.startAttachment = null;
 86→  }
 87→  if ('end' in wallUpdate && !('endAttachment' in wallUpdate)) {
 88→    nextWall.endAttachment = null;
 89→  }
 90→
 91→  return syncWallAttachmentPoints(nextWall, columns);
 92→}
 93→
 94→function projectReducer(state, action) {
 95→  switch (action.type) {
 96→    case 'PROJECT_NEW': {
 97→      const newProject = {
 98→        ...action.project,
 99→        floors: sortFloors(action.project.floors || []),
100→      };
101→      return {
102→        project: newProject,
103→        isDirty: false,
104→        lastSavedAt: null,
105→        savedSnapshot: snapshotProject(newProject),
106→        history: [],
107→        future: [],
108→      };
109→    }
110→
111→    case 'PROJECT_LOAD': {
112→      const loadedProject = {
113→        ...action.project,
114→        floors: sortFloors(action.project.floors || []),
115→      };
116→      return {
117→        project: loadedProject,
118→        isDirty: false,
119→        lastSavedAt: action.savedAt || null,
120→        savedSnapshot: snapshotProject(loadedProject),
121→        history: [],
122→        future: [],
123→      };
124→    }
125→
126→    case 'PROJECT_SET_NAME':
127→      return applyProjectUpdate(state, {
128→        ...state.project,
129→        name: action.name,
130→        updatedAt: new Date().toISOString(),
131→      });
132→
133→    case 'PROJECT_UPDATE':
134→      return applyProjectUpdate(state, {
135→        ...state.project,
136→        ...action.updates,
137→        updatedAt: new Date().toISOString(),
138→      });
139→
140→    case 'FLOOR_ADD':
141→      return replaceFloors(state, [...state.project.floors, action.floor]);
142→
143→    case 'FLOOR_UPDATE':
144→      return updateFloor(state, action.floor.id, (floor) => {
145→        const mergedFloor = {
146→          ...floor,
147→          ...action.floor,
148→        };
149→        const nextElevation = getFloorElevation(mergedFloor);
150→        const deltaElevation = nextElevation - getFloorElevation(floor);
151→        return {
152→          ...shiftFloorAbsoluteElements({
153→            ...mergedFloor,
154→            elevation: getFloorElevation(floor),
155→          }, deltaElevation),
156→          elevation: nextElevation,
157→        };
158→      }, true, { sort: true });
159→
160→    case 'FLOOR_DUPLICATE': {
161→      const duplicatedFloor = action.floor;
162→      const elevationShift = duplicatedFloor.floorToFloorHeight ?? 0;
163→      const insertionLevelIndex = getFloorLevelIndex(duplicatedFloor);
164→
165→      const shiftedFloors = state.project.floors.map((floor) => {
166→        if (getFloorLevelIndex(floor) < insertionLevelIndex) return floor;
167→
168→        const previousLevelIndex = getFloorLevelIndex(floor);
169→        return shiftFloorElevationData({
170→          ...floor,
171→          name: floor.name === getDefaultFloorName(previousLevelIndex)
172→            ? getDefaultFloorName(previousLevelIndex + 1)
173→            : floor.name,
174→          levelIndex: previousLevelIndex + 1,
175→        }, elevationShift);
176→      });
177→
178→      return replaceFloors(state, [...shiftedFloors, duplicatedFloor]);
179→    }
180→
181→    case 'FLOOR_DELETE': {
182→      if (state.project.floors.length <= 1) return state;
183→
184→      const nextProject = replaceDeletedFloorReferences(
185→        {
186→          ...state.project,
187→          floors: state.project.floors.filter((floor) => floor.id !== action.floorId),
188→        },
189→        action.floorId,
190→        action.fallbackFloorId
191→      );
192→
193→      return applyProjectUpdate(state, {
194→        ...nextProject,
195→        updatedAt: new Date().toISOString(),
196→        floors: sortFloors(nextProject.floors),
197→      });
198→    }
199→
200→    case 'SHEET_ADD':
201→      return applyProjectUpdate(state, {
202→        ...state.project,
203→        updatedAt: new Date().toISOString(),
204→        sheets: [...(state.project.sheets || []), action.sheet],
205→      });
206→
207→    case 'SHEET_UPDATE':
208→      return applyProjectUpdate(state, {
209→        ...state.project,
210→        updatedAt: new Date().toISOString(),
211→        sheets: (state.project.sheets || []).map((sheet) => (
212→          sheet.id === action.sheet.id ? { ...sheet, ...action.sheet } : sheet
213→        )),
214→      });
215→
216→    case 'SHEET_DELETE':
217→      return applyProjectUpdate(state, {
218→        ...state.project,
219→        updatedAt: new Date().toISOString(),
220→        sheets: (state.project.sheets || []).filter((sheet) => sheet.id !== action.sheetId),
221→      });
222→
223→    case 'SHEET_VIEWPORT_ADD':
224→      return applyProjectUpdate(state, {
225→        ...state.project,
226→        updatedAt: new Date().toISOString(),
227→        sheets: (state.project.sheets || []).map((sheet) => (
228→          sheet.id === action.sheetId
229→            ? { ...sheet, viewports: [...(sheet.viewports || []), action.viewport] }
230→            : sheet
231→        )),
232→      });
233→
234→    case 'SHEET_VIEWPORT_UPDATE':
235→      return applyProjectUpdate(state, {
236→        ...state.project,
237→        updatedAt: new Date().toISOString(),
238→        sheets: (state.project.sheets || []).map((sheet) => (
239→          sheet.id === action.sheetId
240→            ? {
241→                ...sheet,
242→                viewports: (sheet.viewports || []).map((viewport) => (
243→                  viewport.id === action.viewport.id ? { ...viewport, ...action.viewport } : viewport
244→                )),
245→              }
246→            : sheet
247→        )),
248→      });
249→
250→    case 'SHEET_VIEWPORT_DELETE':
251→      return applyProjectUpdate(state, {
252→        ...state.project,
253→        updatedAt: new Date().toISOString(),
254→        sheets: (state.project.sheets || []).map((sheet) => (
255→          sheet.id === action.sheetId
256→            ? {
257→                ...sheet,
258→                viewports: (sheet.viewports || []).filter((viewport) => viewport.id !== action.viewportId),
259→              }
260→            : sheet
261→        )),
262→      });
263→
264→    case 'WALL_ADD':
265→      return updateFloor(state, action.floorId, f => ({
266→        ...f,
267→        walls: [...f.walls, syncWallAttachmentPoints(action.wall, f.columns || [])],
268→      }));
269→
270→    case 'WALL_UPDATE':
271→      return updateFloor(state, action.floorId, f => ({
272→        ...f,
273→        walls: f.walls.map(w => (
274→          w.id === action.wall.id
275→            ? mergeWallUpdate(w, action.wall, f.columns || [])
276→            : w
277→        )),
278→      }));
279→
280→    case 'WALL_DELETE': {
281→      const wallId = action.wallId;
282→      return updateFloor(state, action.floorId, f => ({
283→        ...f,
284→        walls: f.walls.filter(w => w.id !== wallId),
285→        doors: f.doors.filter(d => d.wallId !== wallId),
286→        windows: f.windows.filter(w => w.wallId !== wallId),
287→      }));
288→    }
289→
290→    case 'DOOR_ADD':
291→      return updateFloor(state, action.floorId, f => ({
292→        ...f,
293→        doors: [...f.doors, action.door],
294→      }));
295→
296→    case 'DOOR_UPDATE':
297→      return updateFloor(state, action.floorId, f => ({
298→        ...f,
299→        doors: f.doors.map(d => d.id === action.door.id ? { ...d, ...action.door } : d),
300→      }));
301→
302→    case 'DOOR_DELETE':
303→      return updateFloor(state, action.floorId, f => ({
304→        ...f,
305→        doors: f.doors.filter(d => d.id !== action.doorId),
306→      }));
307→
308→    case 'WINDOW_ADD':
309→      return updateFloor(state, action.floorId, f => ({
310→        ...f,
311→        windows: [...f.windows, action.window],
312→      }));
313→
314→    case 'WINDOW_UPDATE':
315→      return updateFloor(state, action.floorId, f => ({
316→        ...f,
317→        windows: f.windows.map(w => w.id === action.window.id ? { ...w, ...action.window } : w),
318→      }));
319→
320→    case 'WINDOW_DELETE':
321→      return updateFloor(state, action.floorId, f => ({
322→        ...f,
323→        windows: f.windows.filter(w => w.id !== action.windowId),
324→      }));
325→
326→    case 'BEAM_ADD':
327→      return updateFloor(state, action.floorId, f => ({
328→        ...f,
329→        beams: [...(f.beams || []), action.beam],
330→      }));
331→
332→    case 'BEAM_UPDATE':
333→      return updateFloor(state, action.floorId, f => ({
334→        ...f,
335→        beams: (f.beams || []).map(beam => (
336→          beam.id === action.beam.id ? { ...beam, ...action.beam } : beam
337→        )),
338→      }));
339→
340→    case 'BEAM_DELETE':
341→      return updateFloor(state, action.floorId, f => ({
342→        ...f,
