374→        const nextLandings = (f.landings || []).map(l =>
375→          l.id === action.landing.id ? { ...l, ...action.landing } : l
376→        );
377→        // Cascade: sync all stairs attached to this landing
378→        const nextStairs = (f.stairs || []).map(stair => {
379→          const attachedToStart = stair.startLandingAttachment?.landingId === action.landing.id;
380→          const attachedToEnd = stair.endLandingAttachment?.landingId === action.landing.id;
