546→        )),
547→      }));
548→
549→    case 'MARK_SAVED':
550→      return {
551→        ...state,
552→        isDirty: false,
553→        lastSavedAt: new Date().toISOString(),
554→        savedSnapshot: snapshotProject(state.project),
555→      };
556→
557→    case 'UNDO': {
558→      if (state.history.length === 0) return state;
559→      const previousProject = state.history[state.history.length - 1];
560→      return {
561→        ...state,
562→        project: previousProject,
563→        history: state.history.slice(0, -1),
564→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
565→        isDirty: snapshotProject(previousProject) !== state.savedSnapshot,
566→      };
567→    }
568→
569→    case 'REDO': {
570→      if (state.future.length === 0) return state;
571→      const nextProject = state.future[0];
572→      return {
573→        ...state,
574→        project: nextProject,
575→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
576→        future: state.future.slice(1),
577→        isDirty: snapshotProject(nextProject) !== state.savedSnapshot,
578→      };
579→    }
580→
581→    default:
582→      return state;
583→  }
584→}
