116→export function createSelectHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled }) {
117→  return {
118→    onMouseDown(modelPos, e, toolState) {
119→      if (e.button !== 0) return;
120→
121→      const floor = getFloor(activeFloorId);
122→      if (!floor) return;
123→
124→      // Check if clicking a handle
125→      const target = e.target;
126→      if (target.dataset.handle) {
127→        editorDispatch({
128→          type: 'UPDATE_TOOL_STATE',
129→          payload: {
130→            dragging: true,
131→            dragType: 'handle',
132→            handle: target.dataset.handle,
133→            handleIndex: target.dataset.index != null ? Number(target.dataset.index) : null,
134→            startPos: modelPos,
135→          },
136→        });
137→        return;
138→      }
139→
140→      const hit = hitTest(modelPos, floor, SNAP_DISTANCE_PX / viewport.zoom * 2.5);
141→      if (hit) {
142→        editorDispatch({ type: 'SELECT_OBJECT', id: hit.id, objectType: hit.type });
143→        const draggableTypes = new Set(['wall', 'column', 'fixture', 'door', 'window', 'stair', 'sectionCut', 'landing']);
144→        if (!draggableTypes.has(hit.type)) return;
145→        editorDispatch({
146→          type: 'UPDATE_TOOL_STATE',
147→          payload: {
148→            dragging: true,
149→            dragType: 'move',
150→            startPos: modelPos,
151→            originalPos: modelPos,
152→          },
153→        });
154→      } else {
155→        editorDispatch({
156→          type: 'UPDATE_TOOL_STATE',
157→          payload: {
158→            dragging: true,
159→            dragType: 'marquee',
160→            startPos: modelPos,
161→            currentPos: modelPos,
162→          },
163→        });
164→      }
165→    },
166→
167→    onMouseMove(modelPos, e, toolState, selectedId, selectedType) {
168→      if (toolState.dragging && toolState.dragType === 'marquee') {
169→        editorDispatch({
170→          type: 'UPDATE_TOOL_STATE',
171→          payload: { currentPos: modelPos },
172→        });
173→        return;
174→      }
175→
176→      if (!toolState.dragging || !selectedId) return;
177→
178→      const floor = getFloor(activeFloorId);
179→      if (!floor) return;
180→      const dx = modelPos.x - toolState.startPos.x;
181→      const dy = modelPos.y - toolState.startPos.y;
182→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
183→
184→      if (selectedType === 'wall') {
185→        const wall = floor.walls.find(w => w.id === selectedId);
186→        if (!wall) return;
187→        const resolved = resolveWallEndpoints(wall, floor.columns || []);
188→
189→        if (toolState.dragType === 'handle') {
190→          const handle = toolState.handle;
191→          const oppositeKey = handle === 'start' ? 'end' : 'start';
192→          const oppositePoint = resolved[oppositeKey];
193→          let nextPoint = modelPos;
194→          let nextAttachment = null;
195→
196→          if (e.shiftKey) {
197→            const dx = modelPos.x - oppositePoint.x;
198→            const dy = modelPos.y - oppositePoint.y;
199→            const angle = Math.atan2(dy, dx);
200→            const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
201→            const len = Math.sqrt(dx * dx + dy * dy);
202→            nextPoint = {
203→              x: oppositePoint.x + Math.cos(snapAngle) * len,
204→              y: oppositePoint.y + Math.sin(snapAngle) * len,
205→            };
206→          } else if (snapEnabled) {
207→            const snapResult = snapWallEndpoint(modelPos, {
208→              walls: floor.walls,
209→              columns: floor.columns || [],
210→              snapDist: snapDistModel,
211→              otherPoint: oppositePoint,
212→              ignoreWallId: wall.id,
213→            });
214→            if (snapResult) {
215→              nextPoint = snapResult.point;
216→              nextAttachment = snapResult.attachment;
217→            }
218→          }
219→
220→          if (distance(nextPoint, oppositePoint) < MIN_WALL_LENGTH) return;
221→
222→          dispatch({
223→            type: 'WALL_UPDATE',
224→            floorId: activeFloorId,
225→            wall: {
226→              id: wall.id,
227→              [handle]: nextPoint,
228→              [`${handle}Attachment`]: nextAttachment,
229→            },
230→          });
231→        } else {
232→          let nextStart = { x: resolved.start.x + dx, y: resolved.start.y + dy };
233→          let nextEnd = { x: resolved.end.x + dx, y: resolved.end.y + dy };
234→          let startAttachment = null;
235→          let endAttachment = null;
236→
237→          if (snapEnabled) {
238→            const startSnap = snapWallEndpoint(nextStart, {
239→              walls: floor.walls,
240→              columns: floor.columns || [],
241→              snapDist: snapDistModel,
242→              otherPoint: nextEnd,
243→              ignoreWallId: wall.id,
244→            });
245→            if (startSnap) {
246→              nextStart = startSnap.point;
247→              startAttachment = startSnap.attachment;
248→            }
249→
250→            const endSnap = snapWallEndpoint(nextEnd, {
251→              walls: floor.walls,
252→              columns: floor.columns || [],
253→              snapDist: snapDistModel,
254→              otherPoint: nextStart,
255→              ignoreWallId: wall.id,
256→            });
257→            if (endSnap) {
258→              nextEnd = endSnap.point;
259→              endAttachment = endSnap.attachment;
260→            }
261→          }
262→
263→          if (distance(nextStart, nextEnd) < MIN_WALL_LENGTH) return;
264→
265→          dispatch({
266→            type: 'WALL_UPDATE',
267→            floorId: activeFloorId,
268→            wall: {
269→              id: wall.id,
270→              start: nextStart,
271→              end: nextEnd,
272→              startAttachment,
273→              endAttachment,
274→            },
275→          });
276→        }
277→        editorDispatch({
278→          type: 'UPDATE_TOOL_STATE',
279→          payload: { startPos: modelPos },
280→        });
281→      } else if (selectedType === 'column') {
282→        const col = (floor.columns || []).find(c => c.id === selectedId);
283→        if (!col) return;
284→        dispatch({
285→          type: 'COLUMN_UPDATE',
286→          floorId: activeFloorId,
287→          column: { id: col.id, x: col.x + dx, y: col.y + dy },
288→        });
289→        editorDispatch({
290→          type: 'UPDATE_TOOL_STATE',
291→          payload: { startPos: modelPos },
292→        });
293→      } else if (selectedType === 'fixture') {
294→        const fixture = (floor.fixtures || []).find(f => f.id === selectedId);
295→        if (!fixture) return;
296→        dispatch({
297→          type: 'FIXTURE_UPDATE',
298→          floorId: activeFloorId,
299→          fixture: { id: fixture.id, x: fixture.x + dx, y: fixture.y + dy },
300→        });
301→        editorDispatch({
302→          type: 'UPDATE_TOOL_STATE',
303→          payload: { startPos: modelPos },
304→        });
305→      } else if (selectedType === 'sectionCut') {
306→        const sectionCut = (floor.sectionCuts || []).find(s => s.id === selectedId);
307→        if (!sectionCut) return;
308→
309→        if (toolState.dragType === 'handle') {
310→          const handle = toolState.handle;
311→          const nextSectionCut = handle === 'start'
312→            ? { ...sectionCut, startPoint: modelPos }
313→            : { ...sectionCut, endPoint: modelPos };
314→
315→          if (distance(nextSectionCut.startPoint, nextSectionCut.endPoint) < MIN_WALL_LENGTH) return;
316→
317→          dispatch({
318→            type: 'SECTION_UPDATE',
319→            floorId: activeFloorId,
320→            sectionCut: nextSectionCut,
321→          });
322→        } else {
323→          dispatch({
324→            type: 'SECTION_UPDATE',
325→            floorId: activeFloorId,
326→            sectionCut: {
327→              id: sectionCut.id,
328→              startPoint: {
329→                x: sectionCut.startPoint.x + dx,
330→                y: sectionCut.startPoint.y + dy,
331→              },
332→              endPoint: {
333→                x: sectionCut.endPoint.x + dx,
334→                y: sectionCut.endPoint.y + dy,
335→              },
336→            },
337→          });
338→          editorDispatch({
339→            type: 'UPDATE_TOOL_STATE',
340→            payload: { startPos: modelPos },
341→          });
342→        }
343→      } else if (selectedType === 'beam') {
344→        return;
345→      } else if (selectedType === 'stair') {
346→        const stair = (floor.stairs || []).find(entry => entry.id === selectedId);
347→        if (!stair) return;
348→        dispatch({
349→          type: 'STAIR_UPDATE',
350→          floorId: activeFloorId,
351→          stair: {
352→            id: stair.id,
353→            startPoint: {
354→              x: stair.startPoint.x + dx,
355→              y: stair.startPoint.y + dy,
356→            },
357→          },
358→        });
359→        editorDispatch({
360→          type: 'UPDATE_TOOL_STATE',
361→          payload: { startPos: modelPos },
362→        });
363→      } else if (selectedType === 'landing') {
364→        const landing = (floor.landings || []).find(l => l.id === selectedId);
365→        if (!landing) return;
366→        dispatch({
367→          type: 'LANDING_UPDATE',
368→          floorId: activeFloorId,
369→          landing: {
370→            id: landing.id,
371→            position: {
372→              x: landing.position.x + dx,
373→              y: landing.position.y + dy,
374→            },
375→          },
376→        });
377→        editorDispatch({
378→          type: 'UPDATE_TOOL_STATE',
379→          payload: { startPos: modelPos },
380→        });
381→      } else if (selectedType === 'slab') {
382→        if (toolState.dragType !== 'handle' || toolState.handle !== 'slab-vertex' || toolState.handleIndex == null) {
383→          return;
384→        }
385→        const slab = (floor.slabs || []).find(s => s.id === selectedId);
386→        if (!slab) return;
387→
388→        const boundaryPoints = slab.boundaryPoints.map((point, index) => (
389→          index === toolState.handleIndex ? { x: modelPos.x, y: modelPos.y } : point
390→        ));
391→
392→        dispatch({
393→          type: 'SLAB_UPDATE',
394→          floorId: activeFloorId,
395→          slab: {
396→            id: slab.id,
397→            boundaryPoints,
398→          },
399→        });
400→        editorDispatch({
401→          type: 'UPDATE_TOOL_STATE',
402→          payload: { startPos: modelPos },
403→        });
404→      } else if (selectedType === 'door' || selectedType === 'window') {
405→        // Slide along parent wall
406→        const items = selectedType === 'door' ? floor.doors : floor.windows;
407→        const item = items.find(i => i.id === selectedId);
408→        if (!item) return;
409→
410→        const wall = floor.walls.find(w => w.id === item.wallId);
411→        if (!wall) return;
412→
413→        const newOffset = projectPointOnWall(wall, modelPos);
414→        const halfWidth = item.width / 2;
415→        const maxOffset = wallLength(wall) - halfWidth;
416→        const clampedOffset = Math.max(halfWidth, Math.min(maxOffset, newOffset));
417→
418→        const updateType = selectedType === 'door' ? 'DOOR_UPDATE' : 'WINDOW_UPDATE';
419→        dispatch({
420→          type: updateType,
421→          floorId: activeFloorId,
422→          [selectedType]: { id: item.id, offset: clampedOffset },
423→        });
424→
425→        editorDispatch({
426→          type: 'UPDATE_TOOL_STATE',
427→          payload: { startPos: modelPos },
428→        });
429→      }
430→    },
431→
432→    onMouseUp(modelPos, e, toolState) {
433→      if (toolState.dragging && toolState.dragType === 'marquee') {
434→        const floor = getFloor(activeFloorId);
435→        const bounds = normalizeRectBounds(toolState.startPos || modelPos, toolState.currentPos || modelPos);
436→        const size = rectSize(bounds);
437→        const minimumSize = SNAP_DISTANCE_PX / viewport.zoom;
438→
439→        if (!floor || (size.width < minimumSize && size.height < minimumSize)) {
440→          editorDispatch({ type: 'DESELECT' });
441→        } else {
442→          const regionSelection = collectPlanRegionSelection(floor, bounds);
443→          if (regionSelection.objectCount) {
444→            editorDispatch({
445→              type: 'SET_REGION_SELECTION',
446→              bounds: regionSelection.bounds,
447→              selection: regionSelection.selection,
448→            });
449→          } else {
450→            editorDispatch({ type: 'DESELECT' });
451→          }
452→        }
453→
454→        editorDispatch({
455→          type: 'UPDATE_TOOL_STATE',
456→          payload: {
457→            dragging: false,
458→            dragType: null,
459→            handle: null,
460→            handleIndex: null,
461→            startPos: null,
462→            currentPos: null,
463→          },
464→        });
465→        return;
466→      }
467→
468→      if (toolState.dragging) {
469→        editorDispatch({
470→          type: 'UPDATE_TOOL_STATE',
471→          payload: {
472→            dragging: false,
473→            dragType: null,
474→            handle: null,
475→            handleIndex: null,
476→            startPos: null,
477→            originalPos: null,
478→            currentPos: null,
479→          },
480→        });
481→      }
482→    },
483→
484→    onKeyDown(e, toolState, selectedId, selectedType) {
485→      if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'd' && selectedId && selectedType === 'column') {
486→        e.preventDefault();
487→        const floor = getFloor(activeFloorId);
488→        if (!floor) return;
489→        const column = (floor.columns || []).find(c => c.id === selectedId);
490→        if (!column) return;
491→        const duplicate = duplicateColumn(column);
492→        dispatch({ type: 'COLUMN_DUPLICATE', floorId: activeFloorId, column: duplicate });
493→        editorDispatch({ type: 'SELECT_OBJECT', id: duplicate.id, objectType: 'column' });
494→        return;
495→      }
496→
497→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
498→        const floor = getFloor(activeFloorId);
499→        if (!floor) return;
500→        if (selectedType === 'wall') {
501→          dispatch({ type: 'WALL_DELETE', floorId: activeFloorId, wallId: selectedId });
502→        } else if (selectedType === 'door') {
503→          dispatch({ type: 'DOOR_DELETE', floorId: activeFloorId, doorId: selectedId });
504→        } else if (selectedType === 'window') {
505→          dispatch({ type: 'WINDOW_DELETE', floorId: activeFloorId, windowId: selectedId });
506→        } else if (selectedType === 'column') {
507→          dispatch({ type: 'COLUMN_DELETE', floorId: activeFloorId, columnId: selectedId });
508→        } else if (selectedType === 'fixture') {
509→          dispatch({ type: 'FIXTURE_DELETE', floorId: activeFloorId, fixtureId: selectedId });
510→        } else if (selectedType === 'beam') {
511→          dispatch({ type: 'BEAM_DELETE', floorId: activeFloorId, beamId: selectedId });
512→        } else if (selectedType === 'stair') {
513→          dispatch({ type: 'STAIR_DELETE', floorId: activeFloorId, stairId: selectedId });
514→        } else if (selectedType === 'landing') {
515→          dispatch({ type: 'LANDING_DELETE', floorId: activeFloorId, landingId: selectedId });
516→        } else if (selectedType === 'annotation') {
517→          dispatch({ type: 'ANNOTATION_DELETE', floorId: activeFloorId, annotationId: selectedId });
518→        } else if (selectedType === 'slab') {
519→          dispatch({ type: 'SLAB_DELETE', floorId: activeFloorId, slabId: selectedId });
520→        } else if (selectedType === 'sectionCut') {
521→          dispatch({ type: 'SECTION_DELETE', floorId: activeFloorId, sectionId: selectedId });
522→        } else if (selectedType === 'room') {
523→          dispatch({ type: 'ROOM_DELETE', floorId: activeFloorId, roomId: selectedId });
524→        }
525→        editorDispatch({ type: 'DESELECT' });
526→      }
527→    },
528→
529→    getCursor(toolState) {
530→      if (toolState.dragType === 'marquee') return 'crosshair';
531→      if (toolState.dragging) return 'grabbing';
532→      return 'default';
533→    },
534→  };
535→}
