 30→function editorReducer(state, action) {
 31→  switch (action.type) {
 32→    case 'SET_TOOL':
 33→      return {
 34→        ...clearSelectionState(state),
 35→        activeTool: action.tool,
 36→        toolState: {},
 37→        statusMessage: null,
 38→      };
 39→
 40→    case 'SET_VIEW_MODE':
 41→      return {
 42→        ...clearSelectionState(state),
 43→        workspaceMode: 'model',
 44→        viewMode: normalizeViewMode(action.viewMode),
 45→        activeSectionCutId: action.sectionCutId ?? state.activeSectionCutId,
 46→        viewport: { ...state.modelViewport },
 47→        toolState: {},
 48→        statusMessage: null,
 49→      };
 50→
 51→    case 'SET_WORKSPACE_MODE':
 52→      return {
 53→        ...clearSelectionState(state),
 54→        workspaceMode: action.workspaceMode,
 55→        viewport: action.workspaceMode === 'sheet'
 56→          ? { ...state.sheetViewport }
 57→          : { ...state.modelViewport },
 58→        toolState: {},
 59→        statusMessage: null,
 60→      };
 61→
 62→    case 'SET_ACTIVE_SHEET':
 63→      return {
 64→        ...clearSelectionState(state),
 65→        activeSheetId: action.sheetId,
 66→        statusMessage: null,
 67→      };
 68→
 69→    case 'SELECT_OBJECT':
 70→      return {
 71→        ...clearSelectionState(state),
 72→        selectedId: action.id,
 73→        selectedType: action.objectType,
 74→      };
 75→
 76→    case 'DESELECT':
 77→      return clearSelectionState(state);
 78→
 79→    case 'SET_REGION_SELECTION':
 80→      return {
 81→        ...clearSelectionState(state),
 82→        regionSelection: action.selection && action.bounds
 83→          ? {
 84→              bounds: action.bounds,
 85→              selection: action.selection,
 86→              objectCount: Object.values(action.selection).reduce((count, ids) => count + (ids?.length || 0), 0),
 87→            }
 88→          : null,
 89→      };
 90→
 91→    case 'UPDATE_TOOL_STATE':
 92→      return {
 93→        ...state,
 94→        toolState: { ...state.toolState, ...action.payload },
 95→      };
 96→
 97→    case 'SET_VIEWPORT':
 98→      return {
 99→        ...state,
100→        modelViewport: state.workspaceMode === 'model' ? { ...action.viewport } : state.modelViewport,
101→        sheetViewport: state.workspaceMode === 'sheet' ? { ...action.viewport } : state.sheetViewport,
102→        viewport: { ...action.viewport },
103→      };
104→
105→    case 'PAN':
106→      return {
107→        ...state,
108→        modelViewport: state.workspaceMode === 'model'
109→          ? {
110→              ...state.modelViewport,
111→              panX: state.modelViewport.panX + action.dx,
112→              panY: state.modelViewport.panY + action.dy,
113→            }
114→          : state.modelViewport,
115→        sheetViewport: state.workspaceMode === 'sheet'
116→          ? {
117→              ...state.sheetViewport,
118→              panX: state.sheetViewport.panX + action.dx,
119→              panY: state.sheetViewport.panY + action.dy,
120→            }
121→          : state.sheetViewport,
122→        viewport: {
123→          ...state.viewport,
124→          panX: state.viewport.panX + action.dx,
125→          panY: state.viewport.panY + action.dy,
126→        },
127→      };
128→
129→    case 'ZOOM': {
130→      const { zoom, panX, panY } = action;
131→      return {
132→        ...state,
133→        modelViewport: state.workspaceMode === 'model' ? { zoom, panX, panY } : state.modelViewport,
134→        sheetViewport: state.workspaceMode === 'sheet' ? { zoom, panX, panY } : state.sheetViewport,
135→        viewport: { zoom, panX, panY },
136→      };
137→    }
138→
139→    case 'TOGGLE_GRID':
140→      return { ...state, showGrid: !state.showGrid };
141→
142→    case 'TOGGLE_SNAP':
143→      return { ...state, snapEnabled: !state.snapEnabled };
144→
145→    case 'SET_ACTIVE_FLOOR':
146→      return {
147→        ...clearSelectionState(state),
148→        activeFloorId: action.floorId,
149→        toolState: {},
150→        statusMessage: null,
151→      };
152→
153→    case 'SET_STATUS_MESSAGE':
154→      return { ...state, statusMessage: action.message };
155→
156→    case 'CLEAR_STATUS_MESSAGE':
157→      if (!state.statusMessage) return state;
158→      return { ...state, statusMessage: null };
159→
160→    case 'START_PASTE_PREVIEW':
161→      return {
162→        ...state,
163→        selectedId: null,
164→        selectedType: null,
165→        regionSelection: null,
166→        pastePreview: {
167→          active: true,
168→          point: action.point ?? null,
169→        },
170→      };
171→
172→    case 'UPDATE_PASTE_PREVIEW':
173→      if (!state.pastePreview?.active) return state;
174→      return {
175→        ...state,
176→        pastePreview: {
177→          active: true,
178→          point: action.point,
179→        },
180→      };
181→
182→    case 'CANCEL_PASTE_PREVIEW':
183→      if (!state.pastePreview?.active) return state;
184→      return {
185→        ...state,
186→        pastePreview: {
187→          active: false,
188→          point: null,
189→        },
190→      };
191→
192→    case 'TOGGLE_MAXIMIZE_PANEL':
193→      return {
194→        ...state,
195→        maximizedPanel: state.maximizedPanel === action.panel ? null : action.panel,
196→      };
197→
198→    default:
199→      return state;
200→  }
201→}
