228→export function EditorProvider({ children, initialActiveFloorId = null, availableFloorIds = [] }) {
229→  const [state, dispatch] = useReducer(
230→    editorReducer,
231→    initialActiveFloorId,
232→    createInitialEditorState
233→  );
234→
235→  useEffect(() => {
236→    if (!availableFloorIds.length) {
237→      if (state.activeFloorId !== null) {
238→        dispatch({ type: 'SET_ACTIVE_FLOOR', floorId: null });
239→      }
240→      return;
241→    }
242→
243→    if (!state.activeFloorId || !availableFloorIds.includes(state.activeFloorId)) {
244→      dispatch({ type: 'SET_ACTIVE_FLOOR', floorId: availableFloorIds[0] });
245→    }
246→  }, [availableFloorIds, state.activeFloorId]);
247→
248→  return (
249→    <EditorContext.Provider value={{ state, dispatch }}>
250→      {children}
251→    </EditorContext.Provider>
252→  );
253→}
