 11→function screenToSheet(screenX, screenY, viewport, svgRect) {
 12→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 13→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 14→  return { x, y };
 15→}
 16→
 17→export default function SheetCanvas() {
 18→  const svgRef = useRef(null);
 19→  const dragState = useRef(null);
 20→  const activePointerId = useRef(null);
 21→  const isPanning = useRef(false);
 22→  const lastPanPos = useRef({ x: 0, y: 0 });
 23→
 24→  const { project, dispatch } = useProject();
 25→  const {
 26→    activeSheetId,
 27→    selectedId,
 28→    selectedType,
 29→    viewport,
 30→    dispatch: editorDispatch,
 31→  } = useEditor();
 32→
 33→  const sheet = (project.sheets || []).find((entry) => entry.id === activeSheetId) || null;
 34→  const scene = useMemo(() => buildSheetScene(project, sheet), [project, sheet]);
 35→
 36→  const getSheetPos = useCallback((event) => {
 37→    const rect = svgRef.current.getBoundingClientRect();
 38→    return screenToSheet(event.clientX, event.clientY, viewport, rect);
 39→  }, [viewport]);
 40→
 41→  const updateViewport = useCallback((viewportId, updates) => {
 42→    if (!sheet) return;
 43→    const current = (sheet.viewports || []).find((entry) => entry.id === viewportId);
 44→    if (!current) return;
 45→    const sceneViewport = scene?.viewports.find((entry) => entry.id === viewportId) || null;
 46→    const isManualEdit = ['x', 'y', 'width', 'height', 'rotation'].some((key) => key in updates);
 47→    const baseViewport = sceneViewport
 48→      ? {
 49→          ...current,
 50→          x: sceneViewport.x,
 51→          y: sceneViewport.y,
 52→          width: sceneViewport.width,
 53→          height: sceneViewport.height,
 54→          rotation: sceneViewport.rotation,
 55→        }
 56→      : current;
 57→    const nextViewport = fitViewportToSheet({
 58→      ...baseViewport,
 59→      ...updates,
 60→      lockAutoLayout: 'lockAutoLayout' in updates
 61→        ? updates.lockAutoLayout
 62→        : (isManualEdit ? true : baseViewport.lockAutoLayout),
 63→    }, sheet);
 64→    dispatch({ type: 'SHEET_VIEWPORT_UPDATE', sheetId: sheet.id, viewport: nextViewport });
 65→  }, [dispatch, scene?.viewports, sheet]);
 66→
 67→  const capturePointer = useCallback((pointerId) => {
 68→    if (!svgRef.current) return;
 69→    activePointerId.current = pointerId;
 70→    try {
 71→      svgRef.current.setPointerCapture(pointerId);
 72→    } catch {
 73→      activePointerId.current = pointerId;
 74→    }
 75→  }, []);
 76→
 77→  const releasePointer = useCallback((pointerId = activePointerId.current) => {
 78→    if (!svgRef.current || pointerId == null) {
 79→      activePointerId.current = null;
 80→      return;
 81→    }
 82→    try {
 83→      if (svgRef.current.hasPointerCapture?.(pointerId)) {
 84→        svgRef.current.releasePointerCapture(pointerId);
 85→      }
 86→    } catch {
 87→      // Ignore browsers that reject release calls after capture is already gone.
 88→    }
 89→    activePointerId.current = null;
 90→  }, []);
 91→
 92→  const handlePointerDown = useCallback((event) => {
 93→    if (activePointerId.current !== null && activePointerId.current !== event.pointerId) return;
 94→
 95→    if (event.button === 1 || (event.button === 0 && event.shiftKey)) {
 96→      capturePointer(event.pointerId);
 97→      isPanning.current = true;
 98→      lastPanPos.current = { x: event.clientX, y: event.clientY };
 99→      event.preventDefault();
100→      return;
101→    }
102→
103→    if (event.button !== 0) return;
104→
105→    if (!sheet || !scene) return;
106→
107→    const point = getSheetPos(event);
108→
109→    if (selectedType === 'sheetViewport' && selectedId) {
110→      const selectedVp = scene.viewports.find((entry) => entry.id === selectedId);
111→      if (selectedVp && hitTestViewportRotationHandle(point, selectedVp, 6 / viewport.zoom)) {
112→        const cx = selectedVp.x + selectedVp.width / 2;
113→        const cy = selectedVp.y + selectedVp.height / 2;
114→        dragState.current = {
115→          mode: 'rotate',
116→          viewportId: selectedId,
117→          center: { x: cx, y: cy },
118→          initialRotation: selectedVp.rotation || 0,
119→          startAngle: Math.atan2(point.y - cy, point.x - cx) * (180 / Math.PI),
120→        };
121→        capturePointer(event.pointerId);
122→        event.preventDefault();
123→        return;
124→      }
125→    }
126→
127→    const handleViewportCandidates = selectedType === 'sheetViewport' && selectedId
128→      ? [
129→          ...scene.viewports.filter((entry) => entry.id === selectedId),
130→          ...scene.viewports.filter((entry) => entry.id !== selectedId),
131→        ]
132→      : scene.viewports;
133→
134→    const handleHit = hitTestViewportHandle(point, handleViewportCandidates, 6 / viewport.zoom);
135→
136→    if (handleHit) {
137→      editorDispatch({ type: 'SELECT_OBJECT', id: handleHit.viewportId, objectType: 'sheetViewport' });
138→      const selectedViewport = scene.viewports.find((entry) => entry.id === handleHit.viewportId);
139→      dragState.current = {
140→        mode: 'resize',
141→        viewportId: handleHit.viewportId,
142→        handle: handleHit.handle,
143→        origin: point,
144→        initialViewport: selectedViewport || sheet.viewports.find((entry) => entry.id === handleHit.viewportId),
145→      };
146→      capturePointer(event.pointerId);
147→      event.preventDefault();
148→      return;
149→    }
150→
151→    const viewportHit = hitTestViewport(point, scene.viewports);
152→    if (viewportHit) {
153→      editorDispatch({ type: 'SELECT_OBJECT', id: viewportHit.id, objectType: 'sheetViewport' });
154→      dragState.current = {
155→        mode: 'move',
156→        viewportId: viewportHit.id,
157→        origin: point,
158→        initialViewport: viewportHit,
159→      };
160→      capturePointer(event.pointerId);
161→      event.preventDefault();
162→      return;
163→    }
164→
165→    editorDispatch({ type: 'SELECT_OBJECT', id: sheet.id, objectType: 'sheet' });
166→    dragState.current = null;
167→  }, [activePointerId, capturePointer, editorDispatch, getSheetPos, scene, selectedId, selectedType, sheet, viewport.zoom]);
168→
169→  const handlePointerMove = useCallback((event) => {
170→    if (activePointerId.current !== null && event.pointerId !== activePointerId.current) return;
171→
172→    if (isPanning.current) {
173→      const dx = event.clientX - lastPanPos.current.x;
174→      const dy = event.clientY - lastPanPos.current.y;
175→      editorDispatch({ type: 'PAN', dx, dy });
176→      lastPanPos.current = { x: event.clientX, y: event.clientY };
177→      return;
178→    }
179→
180→    if (!dragState.current || !sheet) return;
181→
182→    const point = getSheetPos(event);
183→    const { mode } = dragState.current;
184→
185→    if (mode === 'rotate') {
186→      const { center, initialRotation, startAngle, viewportId } = dragState.current;
187→      const currentAngle = Math.atan2(point.y - center.y, point.x - center.x) * (180 / Math.PI);
188→      let newRotation = initialRotation + (currentAngle - startAngle);
189→      if (event.shiftKey) {
190→        newRotation = Math.round(newRotation / 15) * 15;
191→      }
192→      newRotation = ((newRotation % 360) + 360) % 360;
193→      updateViewport(viewportId, { rotation: newRotation });
194→      return;
195→    }
196→
197→    const { initialViewport, origin, handle, viewportId } = dragState.current;
198→    const dx = point.x - origin.x;
199→    const dy = point.y - origin.y;
200→
201→    if (mode === 'move') {
202→      updateViewport(viewportId, {
203→        x: initialViewport.x + dx,
204→        y: initialViewport.y + dy,
205→      });
206→      return;
207→    }
208→
209→    const next = {
210→      x: initialViewport.x,
211→      y: initialViewport.y,
212→      width: initialViewport.width,
213→      height: initialViewport.height,
214→    };
215→
216→    if (handle.includes('n')) {
217→      next.y = initialViewport.y + dy;
218→      next.height = initialViewport.height - dy;
219→    }
220→    if (handle.includes('s')) {
221→      next.height = initialViewport.height + dy;
222→    }
223→    if (handle.includes('w')) {
224→      next.x = initialViewport.x + dx;
225→      next.width = initialViewport.width - dx;
226→    }
227→    if (handle.includes('e')) {
228→      next.width = initialViewport.width + dx;
229→    }
230→
231→    updateViewport(viewportId, next);
232→  }, [editorDispatch, getSheetPos, sheet, updateViewport]);
233→
234→  const handlePointerUp = useCallback((event) => {
235→    if (activePointerId.current !== null && event.pointerId !== activePointerId.current) return;
236→    isPanning.current = false;
237→    dragState.current = null;
238→    releasePointer(event.pointerId);
239→  }, [releasePointer]);
240→
241→  const handlePointerCancel = useCallback((event) => {
242→    if (activePointerId.current !== null && event.pointerId !== activePointerId.current) return;
243→    isPanning.current = false;
244→    dragState.current = null;
245→    releasePointer(event.pointerId);
246→  }, [releasePointer]);
247→
248→  const handleWheel = useCallback((event) => {
249→    event.preventDefault();
250→    const rect = svgRef.current.getBoundingClientRect();
251→    const mouseX = event.clientX - rect.left;
252→    const mouseY = event.clientY - rect.top;
253→    const direction = event.deltaY < 0 ? 1 : -1;
254→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
255→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
256→    const panX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
257→    const panY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
258→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX, panY });
259→  }, [editorDispatch, viewport]);
260→
261→  useEffect(() => {
262→    const svg = svgRef.current;
263→    if (!svg) return undefined;
264→    const prevent = (event) => event.preventDefault();
265→    svg.addEventListener('contextmenu', prevent);
266→    svg.addEventListener('wheel', handleWheel, { passive: false });
267→    return () => {
268→      svg.removeEventListener('contextmenu', prevent);
269→      svg.removeEventListener('wheel', handleWheel);
270→    };
271→  }, [handleWheel]);
272→
273→  return (
274→    <div className={styles.canvasContainer}>
275→      <svg
276→        ref={svgRef}
277→        className={styles.svg}
278→        style={{ cursor: dragState.current ? 'grabbing' : 'default', touchAction: 'none' }}
279→        onPointerDown={handlePointerDown}
280→        onPointerMove={handlePointerMove}
281→        onPointerUp={handlePointerUp}
282→        onPointerCancel={handlePointerCancel}
283→      >
284→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
285→          {sheet ? (
286→            <SheetRenderer
287→              project={project}
288→              sheet={sheet}
289→              selectedId={selectedId}
290→              selectedType={selectedType}
291→            />
292→          ) : (
293→            <g className="sheet-empty">
294→              <rect x={0} y={0} width={420} height={297} fill="#f6f7f9" stroke="#d0d6de" strokeDasharray="2 2" />
295→              <text x={210} y={148} textAnchor="middle" dominantBaseline="middle" fill="#66768a" fontSize={12}>
296→                Create a sheet from the sidebar or properties panel.
297→              </text>
298→            </g>
299→          )}
300→        </g>
301→      </svg>
302→      {sheet && scene && (
303→        <svg
304→          data-sheet-export-root="true"
305→          width={scene.paper.width}
306→          height={scene.paper.height}
307→          viewBox={`0 0 ${scene.paper.width} ${scene.paper.height}`}
308→          style={{
309→            position: 'absolute',
310→            width: 0,
311→            height: 0,
312→            overflow: 'hidden',
313→            pointerEvents: 'none',
314→            opacity: 0,
315→          }}
316→          aria-hidden="true"
317→        >
318→          <SheetRenderer
319→            project={project}
320→            sheet={sheet}
321→            selectedId={null}
322→            selectedType={null}
323→          />
324→        </svg>
325→      )}
326→      <div className={styles.statusBar}>
327→        <span>Workspace: sheet</span>
328→        <span>Sheet: {sheet?.title || 'None'}</span>
329→        <span>Zoom: {Math.round(viewport.zoom * 100)}%</span>
330→      </div>
331→    </div>
332→  );
333→}
