 38→    x: border.x + SHEET_TOKENS.innerInset,
 39→    y: border.y + SHEET_TOKENS.innerInset,
 40→    width: border.width - SHEET_TOKENS.innerInset * 2,
 41→    height: border.height - SHEET_TOKENS.innerInset * 2,
 42→  };
 43→
 44→  const footer = {
 45→    x: liveArea.x,
 46→    y: liveArea.y + liveArea.height - SHEET_TOKENS.footerHeight,
 47→    width: liveArea.width,
 48→    height: SHEET_TOKENS.footerHeight,
 49→  };
 50→
 51→  const contentArea = {
 52→    x: liveArea.x,
 53→    y: liveArea.y,
 54→    width: liveArea.width,
 55→    height: footer.y - liveArea.y - SHEET_TOKENS.contentGap,
 56→  };
 57→
 58→  const titleBlock = {
 59→    x: footer.x + footer.width - Math.min(SHEET_TOKENS.titleBlockWidth, footer.width * 0.46),
 60→    y: footer.y,
 61→    width: Math.min(SHEET_TOKENS.titleBlockWidth, footer.width * 0.46),
 62→    height: footer.height,
 63→  };
