420→export function fitViewportToSheet(viewport, sheet) {
421→  const paper = getPaperPreset(sheet.paperSize);
422→  const zones = buildSheetZones(paper);
423→  const captionClearance = getCaptionClearance(viewport);
424→  const captionAbove = viewport.captionPosition === 'above' ? captionClearance : 0;
425→  const captionBelow = viewport.captionPosition === 'below' ? captionClearance : 0;
426→  const width = clamp(
427→    viewport.width,
428→    SHEET_TOKENS.viewportMinWidth,
429→    zones.contentArea.width
430→  );
431→  const height = clamp(
432→    viewport.height,
433→    SHEET_TOKENS.viewportMinHeight,
434→    zones.contentArea.height - captionClearance
435→  );
436→  const maxX = zones.contentArea.x + zones.contentArea.width - width;
437→  const minY = zones.contentArea.y + captionAbove;
438→  const maxY = zones.contentArea.y + zones.contentArea.height - height - captionBelow;
439→
440→  return snapRectToGrid({
441→    ...viewport,
442→    width,
443→    height,
444→    x: clamp(viewport.x, zones.contentArea.x, maxX),
445→    y: clamp(viewport.y, minY, Math.max(minY, maxY)),
446→  });
447→}
