1115→        : (isManualEdit ? true : baseViewport.lockAutoLayout),
1116→    }, sheet);
1117→    dispatch({ type: 'SHEET_VIEWPORT_UPDATE', sheetId: sheet.id, viewport: nextViewport });
1118→  };
1119→
1120→  const floorOptions = getOrderedFloors(project);
1121→  const updateSource = (nextSourceView, nextFloorId = viewport.sourceFloorId, nextRefId) => {
1122→    const floor = floorOptions.find((entry) => entry.id === nextFloorId) || null;
1123→    const refId = nextRefId !== undefined
1124→      ? nextRefId
1125→      : nextSourceView === 'section' ? (floor?.sectionCuts || [])[0]?.id || null : null;
1126→    updateViewport({
1127→      sourceView: nextSourceView,
1128→      sourceFloorId: nextFloorId,
1129→      sourceRefId: refId,
1130→      role: nextSourceView === '3d_preview'
1131→        ? 'supplemental'
1132→        : (viewport.role === 'supplemental' ? 'secondary' : viewport.role),
1133→    });
1134→  };
1135→
1136→  const currentFloor = floorOptions.find((entry) => entry.id === viewport.sourceFloorId) || null;
1137→  const sectionCutOptions = currentFloor?.sectionCuts || [];
1138→
1139→  const source = resolveSheetViewportSource(project, viewport);
1140→
1141→  const toggleLayoutMode = () => {
1142→    if (sheet.layoutTemplate !== 'auto') return;
1143→    if (viewport.lockAutoLayout) {
1144→      updateViewport({ lockAutoLayout: false });
1145→      return;
1146→    }
1147→    updateViewport({
1148→      x: displayedViewport.x,
1149→      y: displayedViewport.y,
1150→      width: displayedViewport.width,
1151→      height: displayedViewport.height,
1152→      rotation: displayedViewport.rotation || 0,
1153→      lockAutoLayout: true,
1154→    });
1155→  };
1156→
1157→  return (
1158→    <div>
1159→      <div className={styles.title}>Sheet Viewport</div>
1160→      <InputField label="Title" value={viewport.title} onChange={(value) => updateViewport({ title: value })} />
1161→      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
1162→        <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Source</label>
1163→        <select
1164→          value={viewport.sourceView}
1165→          onChange={(e) => updateSource(e.target.value)}
1166→          style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-sm)', fontSize: '12px' }}
1167→        >
1168→          <option value="plan">Plan</option>
1169→          <option value="3d_preview">3D Preview</option>
1170→          <option value="section">Section</option>
1171→          <option value="elevation_front">Front Elevation</option>
1172→          <option value="elevation_rear">Rear Elevation</option>
1173→          <option value="elevation_left">Left Elevation</option>
1174→          <option value="elevation_right">Right Elevation</option>
1175→        </select>
1176→      </div>
1177→      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
1178→        <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Floor</label>
1179→        <select
1180→          value={viewport.sourceFloorId || ''}
1181→          onChange={(e) => updateSource(viewport.sourceView, e.target.value)}
1182→          style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-sm)', fontSize: '12px' }}
1183→        >
1184→          {floorOptions.map((floor) => (
1185→            <option key={floor.id} value={floor.id}>{floor.name}</option>
1186→          ))}
1187→        </select>
1188→      </div>
1189→      {viewport.sourceView === 'section' && sectionCutOptions.length > 0 && (
1190→        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
1191→          <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Section Cut</label>
1192→          <select
1193→            value={viewport.sourceRefId || ''}
1194→            onChange={(e) => updateSource('section', viewport.sourceFloorId, e.target.value || null)}
1195→            style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-sm)', fontSize: '12px' }}
1196→          >
1197→            {sectionCutOptions.map((sc) => (
1198→              <option key={sc.id} value={sc.id}>{sc.label || sc.id}</option>
1199→            ))}
1200→          </select>
1201→        </div>
1202→      )}
1203→      <InputField label="Source Label" value={source.title || getViewportSourceLabel(viewport.sourceView)} readOnly />
1204→      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
1205→        <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Role</label>
1206→        <select
1207→          value={viewport.role}
1208→          onChange={(e) => updateViewport({ role: e.target.value })}
1209→          style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-sm)', fontSize: '12px' }}
1210→        >
1211→          <option value="primary">Primary</option>
1212→          <option value="secondary">Secondary</option>
1213→          <option value="detail">Detail</option>
1214→          <option value="supplemental">Supplemental</option>
1215→        </select>
1216→      </div>
1217→      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
1218→        <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Caption</label>
1219→        <select
1220→          value={viewport.captionPosition}
1221→          onChange={(e) => updateViewport({ captionPosition: e.target.value })}
1222→          style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-sm)', fontSize: '12px' }}
1223→        >
1224→          <option value="below">Below</option>
1225→          <option value="above">Above</option>
1226→        </select>
1227→      </div>
1228→      <InputField label="Reference" value={viewport.referenceNote || ''} onChange={(value) => updateViewport({ referenceNote: value })} />
1229→      <InputField
1230→        label="Frame Mode"
1231→        value={sheet.layoutTemplate === 'auto' ? (viewport.lockAutoLayout ? 'Manual' : 'Auto') : 'Manual (sheet)'}
1232→        readOnly
1233→      />
1234→      {sheet.layoutTemplate === 'auto' && (
1235→        <button className={styles.actionBtn} onClick={toggleLayoutMode}>
1236→          {viewport.lockAutoLayout ? 'Use auto layout' : 'Convert to manual frame'}
1237→        </button>
1238→      )}
1239→      <div className={styles.subtitle}>Frame</div>
1240→      <InputField label="X" type="number" suffix={u.suffix} value={u.toDisplay(displayedViewport.x)} onChange={(value) => updateViewport({ x: u.fromDisplay(value) })} />
1241→      <InputField label="Y" type="number" suffix={u.suffix} value={u.toDisplay(displayedViewport.y)} onChange={(value) => updateViewport({ y: u.fromDisplay(value) })} />
1242→      <InputField label="Width" type="number" suffix={u.suffix} value={u.toDisplay(displayedViewport.width)} onChange={(value) => updateViewport({ width: Math.max(20, u.fromDisplay(value)) })} />
1243→      <InputField label="Height" type="number" suffix={u.suffix} value={u.toDisplay(displayedViewport.height)} onChange={(value) => updateViewport({ height: Math.max(20, u.fromDisplay(value)) })} />
1244→      <InputField label="Scale 1:" type="number" value={Math.round(viewport.scale)} onChange={(value) => updateViewport({ scale: Math.max(1, Math.round(value)) })} />
1245→      <InputField label="Rotation" type="number" suffix="°" step={1} value={displayedViewport.rotation || 0} onChange={(value) => updateViewport({ rotation: ((value % 360) + 360) % 360 })} />
1246→    </div>
1247→  );
1248→}
